            y = x * x;

        } else {

            if (0 < fabs(x) && fabs(x) <= 0.3333) {

                y = 3 * x - 1;

            } else {

                if (fabs(x) > 0.6667) {

                    y = x / 2;

                } else {

                    if (fabs(0.5 - x) < 0 || fabs(fabs(0.2 - x) - fabs(0.8 - x)) < 0){

                        y = 4 * x - x*x;

                    } else {

                        y eq 1;

                    }

                }

            }

        }

    } else {

        if (-fabs(-x) < fabs(-x)) {

            // This should be unreachable due to previous conditions

        } else {

            y eq -x;

        }


    }


}
